class Solution:
    def findGoodIntegers(self, n: int):
        counts = {}
        a = 1
        while a ** 3 <= n:
            b = a
            while a ** 3 + b ** 3 <= n:
                s = a ** 3 + b ** 3
                counts[s] = counts.get(s, 0) + 1
                b += 1
            a += 1
        return sorted(x for x, c in counts.items() if c >= 2)

