solutions.javascript:
var findGoodIntegers = function(n) {
    const counts = new Map();
    let a = 1;
    while (2 * a ** 3 <= n) {
        let b = a;
        while (a ** 3 + b ** 3 <= n) {
            const s = a ** 3 + b ** 3;
            counts.set(s, (counts.get(s) || 0) + 1);
            b++;
        }
        a++;
    }
    const result = [];
    for (const [x, c] of counts) {
        if (c >= 2) result.push(x);
    }
    result.sort((x, y) => x - y);
    return result;
};
